module RefModule(
    input clk,
    input reset,
    input signal,
    output reg edge_detected
);

    reg obf_signal_delayed;

    always @(posedge clk) begin
        if (reset) begin
            obf_signal_delayed <= 0;
            edge_detected <= 0;
        end else begin
            edge_detected <= signal & ~obf_signal_delayed;
            obf_signal_delayed <= signal;
        end
    end

endmodule
